async function main() {
  const csvContent = await readFile('transactions.csv');
  const transactions = parseCSV(csvContent);
  const convertedTransactions = convertCurrency(transactions, 0.92);
  const outputCSV = generateCSV(convertedTransactions);
  await writeFile('transactions_eur.csv', outputCSV);
}

function parseCSV(csv: string): Record<string, string>[] {
  const lines = csv.trim().split('\n');
  const headers = lines[0].split(',');
  return lines.slice(1).map(line => {
    const values = line.split(',');
    const entry: Record<string, string> = {};
    headers.forEach((header, index) => {
      entry[header.trim()] = values[index].trim();
    });
    return entry;
  });
}

function convertCurrency(transactions: Record<string, string>[], rate: number): Record<string, string>[] {
  return transactions.map(t => ({
    ...t,
    amount: (parseFloat(t.amount) * rate).toFixed(2)
  }));
}

function generateCSV(data: Record<string, string>[]): string {
  if (data.length === 0) return '';
  const headers = Object.keys(data[0]);
  const headerRow = headers.join(',');
  const rows = data.map(row => headers.map(h => row[h]).join(','));
  return [headerRow, ...rows].join('\n');
}
