function parseLogLine(line: string) {
  const parts = line.trim().split(/\s+/);
  if (parts.length < 3) return null;
  return {
    method: parts[0],
    path: parts[1],
    status: parseInt(parts[2], 10)
  };
}

function generateSummaryRow(logs: any[]) {
  const stats = aggregate(
    logs,
    (acc, log) => {
      acc.total++;
      if (log.status >= 400) acc.errors++;
      return acc;
    },
    { total: 0, errors: 0 }
  );
  return `${new Date().toISOString()},${stats.total},${stats.errors}\n`;
}

async function main() {
  const logStream = pollSource('http://logs.server/access', 1000);
  const batch: any[] = [];

  for await (const line of logStream) {
    const parsed = parseLogLine(line);
    if (parsed) {
      batch.push(parsed);
    }

    if (batch.length >= 50) {
      const summary = generateSummaryRow(batch);
      await writeFile('daily_report.csv', summary);
      batch.length = 0;
    }
  }
}
