async function resolveDnsQuery(domain: string): Promise<string> {
  // 1. Check cache for valid entry
  const cachedRecords = await queryDatabase(
    `SELECT ip, expires_at FROM dns_cache WHERE domain = '${domain}'`
  );

  const now = new Date();
  const validRecord = cachedRecords.find((r: any) => new Date(r.expires_at) > now);

  if (validRecord) {
    return validRecord.ip;
  }

  // 2. Lookup in authoritative nameserver (using DNS-over-HTTPS as proxy)
  const response = await fetchFromApi(`https://dns.google/resolve?name=${domain}&type=A`);

  // 3. Extract IP and TTL
  const answer = response.Answer?.[0];
  if (!answer) throw new Error('Domain not found');

  const ip = answer.data;
  const ttl = answer.TTL;

  // 4. Cache the result with TTL
  const expiresAt = new Date(Date.now() + ttl * 1000).toISOString();
  await writeToDatabase('dns_cache', {
    domain,
    ip,
    expires_at: expiresAt
  });

  return ip;
}
