async function main() {
  const [twitter, reddit, hn] = await Promise.all([
    fetchFromApi('https://api.twitter.com/mentions'),
    fetchFromApi('https://api.reddit.com/search'),
    fetchFromApi('https://api.hackernews.com/search')
  ]);

  const normalize = (items: any[], source: string) => 
    mapItems(items, (item: any) => ({ text: item.text || item.content, source }));

  const mentions = [
    ...normalize(twitter, 'Twitter'),
    ...normalize(reddit, 'Reddit'),
    ...normalize(hn, 'HackerNews')
  ];

  const categories = ['positive', 'neutral', 'negative'];
  const analyzed = await Promise.all(
    mapItems(mentions, async (m) => ({
      ...m,
      sentiment: await llmClassify(m.text, categories)
    }))
  );

  const weights = { positive: 1, neutral: 0, negative: -1 };

  const totalScore = aggregate(analyzed, (sum, m) => sum + weights[m.sentiment], 0);

  const bySource = groupBy(analyzed, 'source');
  const attribution = mapItems(Object.entries(bySource), ([source, items]) => ({
    source,
    score: aggregate(items, (sum, m) => sum + weights[m.sentiment], 0),
    count: items.length
  }));

  return { totalScore, attribution };
}
