function calculateHealthIndex(cpu: number, memory: number, diskLatency: number): number {
  const cpuScore = Math.max(0, 100 - cpu);
  const memScore = Math.max(0, 100 - memory);
  const diskScore = Math.max(0, 100 - (diskLatency / 10));
  return Math.round((cpuScore + memScore + diskScore) / 3);
}

async function main() {
  const cpuStream = pollSource('http://fleet-metrics/cpu', 5000);
  const memStream = pollSource('http://memory-monitor/pressure', 5000);
  const diskStream = pollSource('http://storage-layer/latency', 5000);

  const cpuIterator = cpuStream[Symbol.asyncIterator]();
  const memIterator = memStream[Symbol.asyncIterator]();
  const diskIterator = diskStream[Symbol.asyncIterator]();

  while (true) {
    const [cpuRes, memRes, diskRes] = await Promise.all([
      cpuIterator.next(),
      memIterator.next(),
      diskIterator.next()
    ]);

    if (cpuRes.done || memRes.done || diskRes.done) break;

    const index = calculateHealthIndex(
      cpuRes.value.utilization,
      memRes.value.pressure,
      diskRes.value.latency
    );

    await writeToDatabase('ops_dashboard', {
      timestamp: new Date().toISOString(),
      healthIndex: index
    });
  }
}
