async function handleIncomingRequest(ip: string) {
  const windowMs = 60000;
  const limit = 100;
  const now = Date.now();
  const cutoff = now - windowMs;

  // Retrieve existing requests within the sliding window
  const history = await queryDatabase(
    `SELECT * FROM request_logs WHERE ip = '${ip}' AND timestamp > ${cutoff}`
  );

  if (history.length >= limit) {
    await logToAudit({ ip, status: 429, reason: 'Rate limit exceeded' });
    return { status: 429, body: 'Too Many Requests' };
