interface CartItem {
  id: string;
  name: string;
  price: number;
  quantity: number;
}

interface Cart {
  items: Record<string, CartItem>;
  subtotal: number;
  tax: number;
  shipping: number;
  total: number;
}

interface CartEvent {
  type: 'ADD' | 'REMOVE';
  item: CartItem;
}

async function main() {
  const eventStream = connectWebSocket('wss://api.shop.com/cart-events');

  for await (const event of eventStream) {
    // 1. Retrieve current cart state
    const currentCartData = await queryDatabase('SELECT * FROM carts WHERE user_id = "current_user"');
    const currentCart: Cart = currentCartData.length > 0 ? currentCartData[0] : createEmptyCart();

    // 2. Apply the add/remove event
    const updatedCart = applyEvent(currentCart, event);

    // 3. Reccompute totals (tax and shipping)
    const finalCart = calculateTotals(updatedCart);

    // 4. Persist the updated state
    await writeToDatabase('carts', finalCart);

    // 5. Push summary to frontend
    const summary = `Subtotal: $${finalCart.subtotal}, Tax: $${finalCart.tax}, Shipping: $${finalCart.shipping}, Total: $${finalCart.total}`;
    await sendPushNotification(summary);
  }
}

function createEmptyCart(): Cart {
  return {
    items: {},
    subtotal: 0,
    tax: 0,
    shipping: 0,
    total: 0
  };
}

function applyEvent(cart: Cart, event: CartEvent): Cart {
  const { items } = cart;
  const { item, type } = event;

  if (type === 'ADD') {
    if (items[item.id]) {
      items[item.id].quantity += item.quantity;
    } else {
      items[item.id] = { ...item };
    }
  } else if (type === 'REMOVE') {
    if (items[item.id]) {
      items[item.id].quantity -= item.quantity;
      if (items[item.id].quantity <= 0) {
        delete items[item.id];
      }
    }
  }

  return { ...cart, items };
}

function calculateTotals(cart: Cart): Cart {
  const subtotal = Object.values(cart.items).reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const tax = subtotal * 0.08; // 8% tax rate
  const shipping = subtotal > 0 ? 15.0 : 0.0; // Flat rate shipping
  const total = subtotal + tax + shipping;

  return {
    ...cart,
    subtotal,
    tax,
    shipping,
    total
  };
}
