let leaderboard: { playerId: string; score: number }[] = [];
let lastTop10Hash = "";

async function main() {
  const eventStream = connectWebSocket("wss://game-events.com/scores");

  for await (const event of eventStream) {
    const changed = updateLeaderboard(event.playerId, event.score);
    if (changed) {
      const top10 = leaderboard.slice(0, 10);
      await broadcastLeaderboard(top10);
    }
