function updateLeaderboard(playerId: string, score: number): boolean {
  const existingPlayer = leaderboard.find(p => p.playerId === playerId);

  if (existingPlayer) {
    if (score <= existingPlayer.score) return false;
    existingPlayer.score = score;
  } else {
    leaderboard.push({ playerId, score });
  }

  leaderboard.sort((a, b) => b.score - a.score);

  const currentTop10 = leaderboard.slice(0, 10);
  const currentHash = JSON.stringify(currentTop10);

  if (currentHash !== lastTop10Hash) {
    lastTop10Hash = currentHash;
    return true;
  }

  return false;
