async function sleep(ms: number): Promise<void> {
  return new Promise(resolve => setTimeout(resolve, ms));
}

async function getPriceWithFallback(apiUrl: string, cachePath: string): Promise<number> {
  const maxRetries = 3;
  let lastError: any = null;

  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      await logToAudit({ action: 'api_attempt', attempt, url: apiUrl });
      const data = await fetchFromApi(apiUrl);
      const price = data.price;

      // Update cache on success
      await writeFile(cachePath, JSON.stringify(price));
      return price;
    } catch (error) {
      lastError = error;
      await logToAudit({ action: 'api_error', attempt, error: String(error) });

      if (attempt < maxRetries) {
        const backoffMs = Math.pow(2, attempt) * 1000;
        await sleep(backoffMs);
      }
    }
  }

  // Fallback to cache
  await logToAudit({ action: 'fallback_to_cache', path: cachePath });
  try {
    const cachedContent = await readFile(cachePath);
    return JSON.parse(cachedContent);
  } catch (cacheError) {
    await logToAudit({ action: 'cache_error', error: String(cacheError) });
    throw new Error('All retries failed and cache is unavailable');
  }
}
