type CircuitState = 'CLOSED' | 'OPEN' | 'HALF_OPEN';

const circuitState = {
  status: 'CLOSED' as CircuitState,
  openedAt: 0,
  history: [] as { success: boolean; timestamp: number }[]
};

const WINDOW_MS = 30000;
const FAILURE_THRESHOLD = 0.5;
const TIMEOUT_MS = 10000;

function getDegradedResponse() {
  return { status: 'degraded', message: 'Service unavailable (Circuit Breaker Open)' };
}

function updateHistoryAndCalculateRate(success: boolean): number {
  const now = Date.now();
  circuitState.history.push({ success, timestamp: now });

  // Keep only the last 30 seconds
  circuitState.history = circuitState.history.filter(entry => now - entry.timestamp < WINDOW_MS);

  if (circuitState.history.length === 0) return 0;

  const failures = circuitState.history.filter(entry => !entry.success).length;
  return failures / circuitState.history.length;
}

async function processPayment(amount: number): Promise<any> {
  const now = Date.now();

  // 1. Check Circuit State
  if (circuitState.status === 'OPEN') {
    if (now - circuitState.openedAt > TIMEOUT_MS) {
      // Timeout elapsed, transition to HALF_OPEN to allow a probe
      circuitState.status = 'HALF_OPEN';
    } else {
      // Circuit is still open, short-circuit to degraded response
      return getDegradedResponse();
    }
  }

  // 2. Execute Request
  let success = false;
  let response: any;

  try {
    response = await fetchFromApi('https://api.payment-gateway.com/charge', {
      method: 'POST',
      body: JSON.stringify({ amount })
    });
    success = response.ok !== false; // Simple check for success
  } catch (e) {
    success = false;
  }

  // 3. Update Metrics
  const failureRate = updateHistoryAndCalculateRate(success);

  // 4. Handle State Transitions
  if (success) {
    if (circuitState.status === 'HALF_OPEN') {
      // Probe successful, reset to CLOSED
      circuitState.status = 'CLOSED';
    }
    return response;
  } else {
    if (circuitState.status === 'HALF_OPEN') {
      // Probe failed, reopen immediately
      circuitState.status = 'OPEN';
      circuitState.openedAt = now;
      return getDegradedResponse();
    }

    // Check if we need to open the circuit
    if (failureRate > FAILURE_THRESHOLD) {
      circuitState.status = 'OPEN';
      circuitState.openedAt = now;
      return getDegradedResponse();
    }

    // Failure happened but threshold not met yet
    throw new Error('Payment request failed');
  }
}
